const geminiData = $('HTTP Request').item.json;
let rawText = geminiData.candidates[0].content.parts[0].text;

// Nettoyer le texte avant parsing
rawText = rawText.replace(/```json|```/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch(e) {
  // Extraire subject et html manuellement si JSON cassé
  const subjectMatch = rawText.match(/"subject"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  const htmlMatch = rawText.match(/"html"\s*:\s*"([\s\S]*)"\s*\}?\s*$/);
  parsed = {
    subject: subjectMatch ? subjectMatch[1] : 'TargetUp Group — Solution sur mesure',
    html: htmlMatch ? htmlMatch[1].replace(/\\n/g, '').replace(/\\"/g, '"') : rawText
  };
}

let html = parsed.html;
html = html.replace(/---\s*<br\s*\/?>\s*This email was sent automatically with.*?n8n[^<]*(<\/a>)?/gi, '');
html = html.replace(/This email was sent automatically with n8n/gi, '');

return [{
  json: {
    toEmail:   $('Filter - Email valide et non envoyé').item.json['Email'],
    prenom:    $('Filter - Email valide et non envoyé').item.json['Prenom'],
    nom:       $('Filter - Email valide et non envoyé').item.json['Nom'],
    subject:   parsed.subject,
    emailHtml: html
  },
  binary: {
    brochure: $('Code in JavaScript1').item.binary.brochure
  }
}];
